INSERT INTO quests (manager_id, title, form_data, reward_amount, deadline, status, created_at, updated_at) VALUES
(1, 'React Admin Dashboard 성능 최적화', '{"description":"React로 구축된 관리자 대시보드의 렌더링 성능을 개선하고 번들 사이즈를 줄여주세요. 현재 초기 로딩이 4초 이상 걸리고 있으며 50% 이상 단축이 목표입니다.","techStack":["React","Next.js","TypeScript"],"difficulty":"Intermediate","submissionFormats":["github"]}', 1000000, '2026-05-20 23:59:59', 'OPEN', NOW(), NOW()),
(1, 'Spring Boot REST API 마이크로서비스 설계', '{"description":"주문/결제/유저 서비스를 분리한 마이크로서비스 아키텍처를 Spring Boot로 구현해주세요. JWT 인증, API Gateway, Docker Compose 구성 포함.","techStack":["Java","Spring","Docker"],"difficulty":"Advanced","submissionFormats":["github"]}', 2000000, '2026-06-01 23:59:59', 'OPEN', NOW(), NOW()),
(1, 'React Native 태스크 관리 앱', '{"description":"오프라인 지원과 클라우드 동기화 기능을 갖춘 크로스플랫폼 태스크 관리 앱을 개발해주세요. iOS/Android 모두 동작해야 합니다.","techStack":["React Native","TypeScript","Firebase"],"difficulty":"Intermediate","submissionFormats":["github"]}', 800000, '2026-05-25 23:59:59', 'OPEN', NOW(), NOW()),
(1, 'Next.js 이커머스 풀스택 플랫폼', '{"description":"상품 관리, 장바구니, Stripe 결제 연동, 주문 추적 기능을 포함한 이커머스 플랫폼을 Next.js App Router로 구현해주세요.","techStack":["Next.js","React","TypeScript","Stripe"],"difficulty":"Advanced","submissionFormats":["github"]}', 2500000, '2026-06-10 23:59:59', 'OPEN', NOW(), NOW()),
(1, 'Python FastAPI 데이터 파이프라인', '{"description":"CSV/JSON 파일을 받아 정제 후 PostgreSQL에 적재하는 FastAPI 기반 데이터 파이프라인을 구축해주세요. Celery 비동기 처리 포함.","techStack":["Python","FastAPI","PostgreSQL"],"difficulty":"Intermediate","submissionFormats":["github"]}', 1200000, '2026-05-30 23:59:59', 'OPEN', NOW(), NOW()),
